#include <bits/stdc++.h>
using namespace std;
int t,n,m,p,k;
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d%d%d",&n,&m,&k,&p);
        if(m>=p/n+k)
            printf("Together\n");
        else if(m>=k)
            printf("Chance\n");
        else
            printf("Divide\n");
    }
    return 0;
}
